ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?address ?facilities ?services WHERE {
  ?c a :CondoBuildings .
  ?f a :FacilitiesAndServices .
  ?f p:hasCondoBuildings ?c .
  ?c p:address ?address .
  ?f p:facilities ?facilities .
  ?f p:services ?services .
} }
  component: { SELECT ?address ?facilities WHERE {
  ?c a :CondoBuildings .
  ?f a :FacilitiesAndServices .
  ?f p:hasCondoBuildings ?c .
  ?c p:address ?address .
  ?f p:facilities ?facilities .
} }
  component_2: { SELECT ?address ?services WHERE {
  ?c a :CondoBuildings .
  ?f a :FacilitiesAndServices .
  ?f p:hasCondoBuildings ?c .
  ?c p:address ?address .
  ?f p:services ?services .
} }
}
